package arch.day8;

/**
 * Day 8 basic: package naming, visibility mantra, import reminder.
 */
public class Day8Basic {

    static void sep() {
        System.out.println("----------------------------------------");
    }

    public static void main(String[] args) {
        System.out.println("=== Reverse-DNS packages ===");
        System.out.println("example: com.company.billing.invoice");
        sep();
        System.out.println("=== Visibility (who can see the member) ===");
        System.out.println("private   -> declaring class only");
        System.out.println("default   -> same package");
        System.out.println("protected -> package + subclasses (any package)");
        System.out.println("public    -> everywhere type is reachable");
        sep();
        System.out.println("=== Import is compile-time sugar ===");
        System.out.println("java.util.List can be written as List after import");
        sep();
        System.out.println("=== Single public class per file ===");
        System.out.println("Filename must match the public type");
        sep();
        System.out.println("=== JPMS reminder ===");
        System.out.println("module exports can hide even public types from other modules");
        sep();
        System.out.println("=== Encapsulation cue ===");
        System.out.println("private fields + validated setters preserve invariants");
        sep();
        System.out.println("=== Feature package cue ===");
        System.out.println("group order, catalog, payment slices before giant util bags");
        sep();
        System.out.println("=== Review cue ===");
        System.out.println("draw the tree before adding cyclic imports");
        // Staff quick checks anchor package incidents to tooling evidence.
        System.out.println("=== Package boundary quick checks ===");
        System.out.println("jdeps --print-module-deps | surface split package drift in CI");
        System.out.println("javac -verbose | confirm classpath order when visibility errors spike");
        System.out.println("On-call: capture IllegalAccessError stack + offending module path first");
        System.out.println("done");
    }
}

package arch.day8;

import java.util.ArrayList;
import java.util.List;

/**
 * Day 8 intermediate: package-private helper, imports, protected field via subclass.
 */
class Ledger {
    String label() {
        return "ledger";
    }

    int depth() {
        return 2;
    }
}

public class Day8Intermediate {

    static class Base {
        protected int quota = 5;
        int packOnly = 2;
    }

    static class Sub extends Base {
        int quotaPlusOne() {
            return quota + 1;
        }
    }

    static void printBanner() {
        System.out.println("banner: Day8 intermediate packaging lab");
    }

    static void scenario1() {
        System.out.println("--- Scenario 1: package-private helper same package ---");
        Ledger book = new Ledger();
        System.out.println("helper -> " + book.label());
        System.out.println("nestedMetric -> " + book.depth());
    }

    static void scenario2() {
        System.out.println("--- Scenario 2: simple import vs FQN alias ---");
        List<String> items = new ArrayList<>();
        items.add("alpha");
        items.add("beta");
        items.add("gamma");
        java.util.List<String> same = items;
        System.out.println("first=" + same.get(0));
        System.out.println("size=" + same.size());
    }

    static void scenario3() {
        System.out.println("--- Scenario 3: protected field via subclass ---");
        Sub s = new Sub();
        System.out.println("quotaPlus=" + s.quotaPlusOne());
        System.out.println("lesson: protected survives subclass move across packages");
    }

    static void scenario4() {
        System.out.println("--- Scenario 4: default member same compilation unit ---");
        Base b = new Base();
        System.out.println("packOnlyVisibleHere=" + b.packOnly);
        System.out.println("note: default does not reach other packages");
        System.out.println("note: pair with matrix-row exercise output");
    }

    static void printFooter() {
        System.out.println("footer: align with assignment visibility matrix");
    }

    public static void main(String[] args) {
        printBanner();
        System.out.println("context: package-private leaks show up as linkage errors at runtime");
        System.out.println("context: jdeps maps compile-time module boundaries before deploy");
        scenario1();
        scenario2();
        scenario3();
        scenario4();
        printFooter();
    }
}

package arch.day8;

/**
 * Day 8 advanced: ecommerce path sketch, modifier table, API checklist.
 */
public class Day8Advanced {

    static void spacer() {
        System.out.println("---");
    }

    static void preamble() {
        System.out.println("preface: advanced lab prints three separated decision blocks");
    }

    static void block1() {
        System.out.println("=== Block 1: ecommerce package sketch (paths) ===");
        System.out.println("com.shop.order.Order");
        System.out.println("com.shop.order.OrderService");
        System.out.println("com.shop.order.OrderRepository");
        System.out.println("com.shop.catalog.Product");
        System.out.println("com.shop.catalog.ProductService");
        System.out.println("com.shop.customer.Customer");
        System.out.println("com.shop.customer.CustomerRepository");
        System.out.println("com.shop.payment.PaymentGateway");
        System.out.println("com.shop.shared.Money");
        System.out.println("com.shop.support.Ticket");
        System.out.println("legend: feature folders before dumping util");
        System.out.println("tip: align packages with team ownership boundaries");
        System.out.println();
    }

    static void block2() {
        System.out.println("=== Block 2: modifier recap table ===");
        System.out.println("modifier | class | pkg | sub(other pkg) | world");
        System.out.println("---------|-------|-----|----------------|------");
        System.out.println("private  | yes   | no  | no             | no");
        System.out.println("default  | yes   | yes | no             | no");
        System.out.println("protected| yes   | yes | yes            | no");
        System.out.println("public   | yes   | yes | yes            | yes");
        System.out.println("footnote: memorize before whiteboard interviews");
        System.out.println("drill: explain why default fails for distant subclasses");
        System.out.println();
    }

    static void block3() {
        System.out.println("=== Block 3: API hygiene checklist ===");
        System.out.println("1) expose interfaces from stable packages");
        System.out.println("2) keep concrete services package-private when possible");
        System.out.println("3) avoid public mutable fields on shared DTOs");
        System.out.println("4) document protected template hooks deliberately");
        System.out.println("5) fail CI on package cycles when tooling supports it");
        System.out.println("6) prefer explicit imports in shared modules");
        System.out.println("7) add japicmp or equivalent for library releases");
        System.out.println("8) pair package moves with consumer migration notes");
        System.out.println("9) add ArchUnit or similar rules for forbidden imports");
        System.out.println("10) treat test-only widened visibility as a smell");
        System.out.println("11) schedule quarterly package graph reviews with architects");
        System.out.println("12) log public API changes in release notes for partners");
        System.out.println("review complete");
    }

    static void epilogue() {
        System.out.println("postscript: tie rows to Person validation exercise");
        System.out.println("closing: rehearse matrix before mock interviews");
        System.out.println("eof");
    }

    public static void main(String[] args) {
        System.out.println("banner: Day8 advanced packaging lab");
        preamble();
        block1();
        spacer();
        block2();
        spacer();
        block3();
        epilogue();
    }
}

