package arch.day8;

/**
 * Day 8 exercise — maps to assignments_phase1.json Day 8 prompts.
 */
public class Day8Exercise {

    public static class Person {
        private String name;
        private int age;
        private String email;

        public Person(String name, int age, String email) {
            this.name = name;
            setAge(age);
            setEmail(email);
        }

        public String getName() {
            return name;
        }

        public int getAge() {
            return age;
        }

        public String getEmail() {
            return email;
        }

        public void setAge(int age) {
            if (age < 0 || age > 150) {
                throw new IllegalArgumentException("Invalid age: " + age);
            }
            this.age = age;
        }

        public void setEmail(String email) {
            if (email == null || !email.contains("@")) {
                throw new IllegalArgumentException("Invalid email: " + email);
            }
            this.email = email;
        }

        @Override
        public String toString() {
            return "Person{name='" + name + "', age=" + age + ", email='" + email + "'}";
        }
    }

    public static void main(String[] args) {
        System.out.println("matrix-row: public -> visible wherever the type is reachable");
        System.out.println("matrix-row: protected -> package + subclasses even in other packages");
        System.out.println("matrix-row: default -> same package only, not other-package subclasses");
        System.out.println("matrix-row: private -> declaring top-level class only");
        System.out.println("encap: public fields skip validation hooks callers can break invariants");
        System.out.println("encap: private fields force traffic through methods that can validate");
        System.out.println("encap: setters centralise rules logging and future representation changes");
        System.out.println("pkg: com.shop.order.Order");
        System.out.println("pkg: com.shop.order.OrderService");
        System.out.println("pkg: com.shop.order.OrderRepository");
        System.out.println("pkg: com.shop.catalog.Product");
        System.out.println("pkg: com.shop.customer.Customer");
        System.out.println("pkg: com.shop.payment.PaymentGateway");

        // Person would normally live as a top-level class in a domain package; nested here for the exercise file.
        Person p = new Person("Alice", 30, "alice@example.com");
        System.out.println(p);
        p.setAge(31);
        System.out.println("Updated age: " + p.getAge());
    }
}

